{"format":"sql","data":"-- Database Export\n-- Generated on: 2026-05-19T00:48:25.970Z\n-- Format: SQL\n-- Include Data: true\n-- Row Limit: 1000 rows per table\n\n-- Table: advertisements\nCREATE TABLE IF NOT EXISTS advertisements (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, business_name text NOT NULL, industry text NOT NULL, address text NOT NULL, contact_info text NOT NULL, website_url text NOT NULL, image_url text NOT NULL, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Foreign key constraints for table: advertisements\nALTER TABLE advertisements ADD CONSTRAINT advertisements_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: advertisements\nALTER TABLE advertisements ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: advertisements\nCREATE POLICY \"Admins can manage advertisements of their neighborhood\" ON advertisements FOR ALL TO authenticated USING (is_admin_of(neighborhood_id));\nCREATE POLICY \"Anyone can read advertisements\" ON advertisements FOR SELECT TO public USING (true);\nCREATE POLICY \"Super admins can manage advertisements\" ON advertisements FOR ALL TO authenticated USING (is_super_admin());\nCREATE POLICY project_admin_policy ON advertisements FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Data for table: advertisements\nINSERT INTO advertisements (id, neighborhood_id, business_name, industry, address, contact_info, website_url, image_url, created_at) VALUES ('04b30e6f-1338-46d8-967e-dd54b5e6affc', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Baba''s Pantry', 'restaurant Middle-Eastern', '', '(816) 702-0045', 'https://www.babaspantrykc.com/', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/ad-media/objects/ads%2Fad-1776807281257.jpg', '2026-04-21T21:34:43.801Z');\nINSERT INTO advertisements (id, neighborhood_id, business_name, industry, address, contact_info, website_url, image_url, created_at) VALUES ('3f330f1a-8afd-4cff-8fd3-8fd92c0e4d1a', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Té Amo Café', 'Cafe', '7932 W 151st St, Overland Park, KS 66223', '(945) 342-9762', 'https://www.instagram.com/teamocafe_kc', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/ad-media/objects/ads%2Fad-1776888218230.jpg', '2026-04-22T20:03:40.824Z');\nINSERT INTO advertisements (id, neighborhood_id, business_name, industry, address, contact_info, website_url, image_url, created_at) VALUES ('28020e02-e870-42b9-9f0f-6706a9557af0', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Southside Mafia Pizzeria', 'Restaurant', '10328 Blue Ridge Blvd, Kansas City, MO 64134', '(816) 255-2621', 'https://www.southsidemafiapizzeria.com', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/ad-media/objects/ads%2Fad-1778211497461.jpg', '2026-05-08T03:38:19.262Z');\nINSERT INTO advertisements (id, neighborhood_id, business_name, industry, address, contact_info, website_url, image_url, created_at) VALUES ('03910f92-a5d9-416c-a19d-eab431789155', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Kim Mohammadi', 'Car Dealership', '220 West 103rd Street Kansas City, MO 64114', '(816) 844-6402', 'https://www.jaywolfehonda.com', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/ad-media/objects/ads%2Fad-1778211674852.jpg', '2026-05-08T03:41:16.528Z');\nINSERT INTO advertisements (id, neighborhood_id, business_name, industry, address, contact_info, website_url, image_url, created_at) VALUES ('e8b3a67f-ec3a-432f-932e-4a18ccebf511', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Beard Luv', 'Retail', 'Kansas City MO 64132', '(816)-317-4467', 'https://www.beardluv.com/', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/ad-media/objects/ads%2Fad-1778449288655.jpg', '2026-05-10T21:41:31.279Z');\nINSERT INTO advertisements (id, neighborhood_id, business_name, industry, address, contact_info, website_url, image_url, created_at) VALUES ('87c67a27-0012-412e-9232-34976c1ab7ec', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Nur Imports', 'Retail', '9520 James A Reed Rd A, Kansas City, MO', '(816) 763-1155', 'https://www.facebook.com/nurimports/', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/ad-media/objects/ads%2Fad-1776909891040.jpg', '2026-05-18T06:13:38.188Z');\nINSERT INTO advertisements (id, neighborhood_id, business_name, industry, address, contact_info, website_url, image_url, created_at) VALUES ('e78bfced-b6c8-4f02-83d3-1e2ab3e0eabd', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Shahrazad International Market', 'Grocery store', '12605 Metcalf Ave, Overland Park, KS 66213', '(913) 338-2250', 'https://www.facebook.com/ShahrazadCafe/', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/ad-media/objects/ads%2Fad-1779149915495.jpg', '2026-05-19T00:18:37.535Z');\n\n-- Table: announcements\nCREATE TABLE IF NOT EXISTS announcements (id uuid NOT NULL DEFAULT gen_random_uuid(), title text NOT NULL, content text NOT NULL, category text NOT NULL, author_id uuid, images ARRAY DEFAULT '{}'::text[], attachments ARRAY DEFAULT '{}'::text[], created_at timestamptz DEFAULT now(), neighborhood_id uuid NOT NULL, status text DEFAULT 'pending'::text, updated_at timestamptz DEFAULT now());\n\n-- Foreign key constraints for table: announcements\nALTER TABLE announcements ADD CONSTRAINT announcements_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id);\nALTER TABLE announcements ADD CONSTRAINT fk_announcements_user_profile FOREIGN KEY (author_id) REFERENCES user_profiles (user_id);\n\n-- RLS enabled for table: announcements\nALTER TABLE announcements ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: announcements\nCREATE POLICY authenticated_insert ON announcements FOR INSERT TO public WITH CHECK ((auth.role() = 'authenticated'::text));\nCREATE POLICY owner_update ON announcements FOR UPDATE TO public USING ((auth.uid() = author_id));\nCREATE POLICY project_admin_policy ON announcements FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read ON announcements FOR SELECT TO public USING (true);\n\n-- Data for table: announcements\nINSERT INTO announcements (id, title, content, category, author_id, images, attachments, created_at, neighborhood_id, status, updated_at) VALUES ('8181bf76-1a6f-4884-b9e3-d591b7c92d15', 'Election is in a few weeks', 'I''m reaching out to all LVW members to ask if any of you would like to submit their profile to be a candidate for the next election', 'General Info', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', '[]', '[]', '2026-03-15T13:33:23.625Z', '785dce54-2952-466a-9ba3-79aa59640aa0', 'approved', '2026-04-13T00:41:16.432Z');\nINSERT INTO announcements (id, title, content, category, author_id, images, attachments, created_at, neighborhood_id, status, updated_at) VALUES ('35d3ce69-2a4a-45c9-9f1d-10274c7d35e9', 'Dogs are running loose', 'On Mar 14, while driving out of my court yard around 5 pm, I noticed a big dog (Boxer or Pit bull) running around so I drove near the office and luckily got the help of one of the maintenance people to get the dog out of the area. Kids were playing in the tennis court and I was very worried of getting attacked by the dog. So, if you see a stray dog do not hesitate to call the office or the security.', 'General Info', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', '[]', '[]', '2026-03-15T14:29:44.407Z', '785dce54-2952-466a-9ba3-79aa59640aa0', 'approved', '2026-04-13T00:41:16.432Z');\n\n-- Table: board_positions\nCREATE TABLE IF NOT EXISTS board_positions (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, title text NOT NULL, description text, is_open boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- RLS enabled for table: board_positions\nALTER TABLE board_positions ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: board_positions\nCREATE POLICY \"Members can read board positions\" ON board_positions FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = board_positions.neighborhood_id)))) OR (EXISTS ( SELECT 1\n   FROM user_profiles\n  WHERE ((user_profiles.user_id = auth.uid()) AND (user_profiles.global_role = 'super_admin'::global_role))))));\nCREATE POLICY \"Super admins can manage board positions\" ON board_positions FOR ALL TO public USING ((EXISTS ( SELECT 1\n   FROM user_profiles\n  WHERE ((user_profiles.user_id = auth.uid()) AND (user_profiles.global_role = 'super_admin'::global_role)))));\nCREATE POLICY project_admin_policy ON board_positions FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Triggers for table: board_positions\nCREATE TRIGGER on_board_positions_updated BEFORE UPDATE ON board_positions FOR EACH ROW EXECUTE FUNCTION handle_updated_at();\n\n-- Data for table: board_positions\nINSERT INTO board_positions (id, neighborhood_id, title, description, is_open, created_at, updated_at) VALUES ('5888ad76-f8f2-4e3f-ab7a-1e6481bf0a1a', '785dce54-2952-466a-9ba3-79aa59640aa0', 'President', 'Oversees the entire community association and chairs all meetings.', true, '2026-03-17T13:31:12.034Z', '2026-03-17T13:31:12.034Z');\nINSERT INTO board_positions (id, neighborhood_id, title, description, is_open, created_at, updated_at) VALUES ('9459c48f-53dd-4650-84b2-e6e31daba9b9', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Vice President', 'Assists the president and steps in during their absence.', true, '2026-03-17T13:31:12.034Z', '2026-03-17T13:31:12.034Z');\nINSERT INTO board_positions (id, neighborhood_id, title, description, is_open, created_at, updated_at) VALUES ('8dd5f4cc-a020-4f76-9601-0e2e0d89d2de', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Treasurer', 'Manages the community budget, finances, and fee collection.', true, '2026-03-17T13:31:12.034Z', '2026-03-17T13:31:12.034Z');\nINSERT INTO board_positions (id, neighborhood_id, title, description, is_open, created_at, updated_at) VALUES ('c20ff6b7-61fa-4eb3-8ce1-055e4ab91f08', '785dce54-2952-466a-9ba3-79aa59640aa0', 'Secretary', 'Maintains all records, minutes of meetings, and official documents.', true, '2026-03-17T13:31:12.034Z', '2026-03-17T13:31:12.034Z');\n\n-- Table: candidate_answers\nCREATE TABLE IF NOT EXISTS candidate_answers (id uuid NOT NULL DEFAULT gen_random_uuid(), question_id uuid, content text NOT NULL, created_at timestamptz DEFAULT now());\n\n-- Foreign key constraints for table: candidate_answers\nALTER TABLE candidate_answers ADD CONSTRAINT candidate_answers_question_id_fkey FOREIGN KEY (question_id) REFERENCES candidate_questions (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: candidate_answers\nALTER TABLE candidate_answers ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: candidate_answers\nCREATE POLICY owner_write_candidate_answers ON candidate_answers FOR INSERT TO public WITH CHECK ((auth.uid() IN ( SELECT c.user_id\n   FROM (candidates c\n     JOIN candidate_questions q ON ((c.id = q.candidate_id)))\n  WHERE (q.id = candidate_answers.question_id))));\nCREATE POLICY project_admin_policy ON candidate_answers FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read_candidate_answers ON candidate_answers FOR SELECT TO public USING (true);\n\n-- Table: candidate_questions\nCREATE TABLE IF NOT EXISTS candidate_questions (id uuid NOT NULL DEFAULT gen_random_uuid(), candidate_id uuid, asked_by uuid, content text NOT NULL, created_at timestamptz DEFAULT now());\n\n-- Foreign key constraints for table: candidate_questions\nALTER TABLE candidate_questions ADD CONSTRAINT candidate_questions_candidate_id_fkey FOREIGN KEY (candidate_id) REFERENCES candidates (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: candidate_questions\nALTER TABLE candidate_questions ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: candidate_questions\nCREATE POLICY owner_write_candidate_questions ON candidate_questions FOR INSERT TO public WITH CHECK ((auth.uid() = asked_by));\nCREATE POLICY project_admin_policy ON candidate_questions FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read_candidate_questions ON candidate_questions FOR SELECT TO public USING (true);\n\n-- Table: candidates\nCREATE TABLE IF NOT EXISTS candidates (id uuid NOT NULL DEFAULT gen_random_uuid(), poll_id uuid, user_id uuid, bio text, assets text, image_url text, created_at timestamptz DEFAULT now());\n\n-- Indexes for table: candidates\nCREATE UNIQUE INDEX candidates_poll_id_user_id_key ON public.candidates USING btree (poll_id, user_id);\n\n-- Foreign key constraints for table: candidates\nALTER TABLE candidates ADD CONSTRAINT candidates_poll_id_fkey FOREIGN KEY (poll_id) REFERENCES polls (id) ON DELETE CASCADE;\nALTER TABLE candidates ADD CONSTRAINT candidates_user_id_fkey FOREIGN KEY (user_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: candidates\nALTER TABLE candidates ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: candidates\nCREATE POLICY owner_update_candidates ON candidates FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY owner_write_candidates ON candidates FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON candidates FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read_candidates ON candidates FOR SELECT TO public USING (true);\n\n-- Data for table: candidates\nINSERT INTO candidates (id, poll_id, user_id, bio, assets, image_url, created_at) VALUES ('3a3a8092-ab6f-4a58-a9c0-084f65de6234', '52020fe2-80c9-46ac-84e8-8bfaac5e1d4b', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', 'I am passionate about our community and want to help improve our amenities and safety.', 'Ex-auditor with strong financial oversight skills.', NULL, '2026-03-17T13:35:39.864Z');\n\n-- Table: classified_ads\nCREATE TABLE IF NOT EXISTS classified_ads (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid, title text NOT NULL, price text NOT NULL, description text NOT NULL, contact_info text NOT NULL, image_url text, created_at timestamptz DEFAULT now(), neighborhood_id uuid, category text, price_numeric numeric DEFAULT 0, fee_paid numeric DEFAULT 0, status text DEFAULT 'active'::text, expires_at timestamptz DEFAULT (now() + '30 days'::interval));\n\n-- Foreign key constraints for table: classified_ads\nALTER TABLE classified_ads ADD CONSTRAINT classified_ads_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\nALTER TABLE classified_ads ADD CONSTRAINT fk_classified_ads_user_profile FOREIGN KEY (user_id) REFERENCES user_profiles (user_id);\n\n-- RLS enabled for table: classified_ads\nALTER TABLE classified_ads ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: classified_ads\nCREATE POLICY \"Authenticated members can insert classified ads\" ON classified_ads FOR INSERT TO public WITH CHECK (((auth.uid() = user_id) AND (EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = classified_ads.neighborhood_id))))));\nCREATE POLICY \"Members can read neighborhood classified ads\" ON classified_ads FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = classified_ads.neighborhood_id)))) OR is_super_admin()));\nCREATE POLICY owner_delete_classified_ads ON classified_ads FOR DELETE TO public USING ((auth.uid() = user_id));\nCREATE POLICY owner_update_classified_ads ON classified_ads FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON classified_ads FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Data for table: classified_ads\nINSERT INTO classified_ads (id, user_id, title, price, description, contact_info, image_url, created_at, neighborhood_id, category, price_numeric, fee_paid, status, expires_at) VALUES ('f2933553-2131-44e5-8f80-16c1839b5e44', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', 'Klipsch Sub-10 + Klipsch Center Speaker', '160', 'Klipsch Sub-10 powered subwoofer + Klipsch Quintet III center speaker.\n\nBoth in excellent working condition.\n\nDeep clean bass + clear dialogue.\n\nIncludes RCA cable.\n\n$160 for both.\n\nPickup in Kansas City.\n\nAvailable tonight or tomorrow morning.', 'Simon - 8168246870', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/classified-media/objects/classifieds%2F8239b06a-dcae-4ccf-9543-d594cd8f7e65-1773874358941.jpg', '2026-03-18T22:52:39.887Z', '785dce54-2952-466a-9ba3-79aa59640aa0', NULL, '0.00', '0.00', 'active', NULL);\n\n-- Table: classified_ads_payments\nCREATE TABLE IF NOT EXISTS classified_ads_payments (id uuid NOT NULL DEFAULT gen_random_uuid(), ad_id uuid NOT NULL, user_id uuid NOT NULL, neighborhood_id uuid NOT NULL, amount numeric NOT NULL, stripe_session_id text, payment_status text DEFAULT 'pending'::text, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Foreign key constraints for table: classified_ads_payments\nALTER TABLE classified_ads_payments ADD CONSTRAINT classified_ads_payments_ad_id_fkey FOREIGN KEY (ad_id) REFERENCES classified_ads (id) ON DELETE CASCADE;\nALTER TABLE classified_ads_payments ADD CONSTRAINT classified_ads_payments_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\nALTER TABLE classified_ads_payments ADD CONSTRAINT classified_ads_payments_user_id_fkey FOREIGN KEY (user_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: classified_ads_payments\nALTER TABLE classified_ads_payments ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: classified_ads_payments\nCREATE POLICY \"Admins can read payments for their neighborhood\" ON classified_ads_payments FOR SELECT TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Users can read their own ad payments\" ON classified_ads_payments FOR SELECT TO public USING (((user_id = auth.uid()) OR is_super_admin()));\nCREATE POLICY \"Users can read their own payments\" ON classified_ads_payments FOR SELECT TO public USING (((user_id = auth.uid()) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON classified_ads_payments FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: classified_ads_settings\nCREATE TABLE IF NOT EXISTS classified_ads_settings (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, is_monetization_enabled boolean DEFAULT false, max_ads_resident integer DEFAULT 5, max_ads_moderator integer DEFAULT 10, max_ads_admin integer DEFAULT 20, ad_expiry_days integer DEFAULT 30, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Indexes for table: classified_ads_settings\nCREATE UNIQUE INDEX classified_ads_settings_neighborhood_id_key ON public.classified_ads_settings USING btree (neighborhood_id);\n\n-- Foreign key constraints for table: classified_ads_settings\nALTER TABLE classified_ads_settings ADD CONSTRAINT classified_ads_settings_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: classified_ads_settings\nALTER TABLE classified_ads_settings ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: classified_ads_settings\nCREATE POLICY \"Admins can manage classified settings\" ON classified_ads_settings FOR ALL TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Members can read neighborhood classified settings\" ON classified_ads_settings FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = classified_ads_settings.neighborhood_id)))) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON classified_ads_settings FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Triggers for table: classified_ads_settings\nCREATE TRIGGER on_classified_ads_settings_updated BEFORE UPDATE ON classified_ads_settings FOR EACH ROW EXECUTE FUNCTION handle_updated_at();\n\n-- Table: content_reports\nCREATE TABLE IF NOT EXISTS content_reports (id uuid NOT NULL DEFAULT gen_random_uuid(), reporter_id uuid NOT NULL, neighborhood_id uuid NOT NULL, entity_type text NOT NULL, entity_id uuid NOT NULL, reason text NOT NULL, status text DEFAULT 'pending'::text, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Foreign key constraints for table: content_reports\nALTER TABLE content_reports ADD CONSTRAINT content_reports_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\nALTER TABLE content_reports ADD CONSTRAINT content_reports_reporter_id_fkey FOREIGN KEY (reporter_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: content_reports\nALTER TABLE content_reports ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: content_reports\nCREATE POLICY \"Moderators can view reports for their neighborhood\" ON content_reports FOR SELECT TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin() OR (EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = content_reports.neighborhood_id) AND (user_neighborhoods.role = ANY (ARRAY['admin'::text, 'moderator'::text])))))));\nCREATE POLICY \"Users can insert their own reports\" ON content_reports FOR INSERT TO public WITH CHECK ((auth.uid() = reporter_id));\nCREATE POLICY project_admin_policy ON content_reports FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: conversations\nCREATE TABLE IF NOT EXISTS conversations (id uuid NOT NULL DEFAULT gen_random_uuid(), participant_1_id uuid NOT NULL, participant_2_id uuid NOT NULL, neighborhood_id uuid NOT NULL, last_message_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Indexes for table: conversations\nCREATE UNIQUE INDEX conversations_participant_1_id_participant_2_id_neighborhoo_key ON public.conversations USING btree (participant_1_id, participant_2_id, neighborhood_id);\n\n-- Foreign key constraints for table: conversations\nALTER TABLE conversations ADD CONSTRAINT conversations_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\nALTER TABLE conversations ADD CONSTRAINT conversations_participant_1_id_fkey FOREIGN KEY (participant_1_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\nALTER TABLE conversations ADD CONSTRAINT conversations_participant_2_id_fkey FOREIGN KEY (participant_2_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: conversations\nALTER TABLE conversations ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: conversations\nCREATE POLICY \"Users can create conversations if they are members\" ON conversations FOR INSERT TO public WITH CHECK ((((auth.uid() = participant_1_id) OR (auth.uid() = participant_2_id)) AND (EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = conversations.neighborhood_id))))));\nCREATE POLICY \"Users can see their own conversations\" ON conversations FOR SELECT TO public USING ((((auth.uid() = participant_1_id) OR (auth.uid() = participant_2_id)) OR is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON conversations FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: daily_spins\nCREATE TABLE IF NOT EXISTS daily_spins (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid NOT NULL, neighborhood_id uuid NOT NULL, spin_date date NOT NULL DEFAULT CURRENT_DATE, result_points integer DEFAULT 0, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Indexes for table: daily_spins\nCREATE UNIQUE INDEX daily_spins_user_id_neighborhood_id_spin_date_key ON public.daily_spins USING btree (user_id, neighborhood_id, spin_date);\n\n-- Foreign key constraints for table: daily_spins\nALTER TABLE daily_spins ADD CONSTRAINT daily_spins_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\nALTER TABLE daily_spins ADD CONSTRAINT daily_spins_user_id_fkey FOREIGN KEY (user_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: daily_spins\nALTER TABLE daily_spins ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: daily_spins\nCREATE POLICY \"Admins can see spins for their neighborhood\" ON daily_spins FOR SELECT TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Users can see their own spins\" ON daily_spins FOR SELECT TO public USING (((user_id = auth.uid()) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON daily_spins FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: events\nCREATE TABLE IF NOT EXISTS events (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid, title text NOT NULL, details text NOT NULL, organizer text NOT NULL, venue text NOT NULL, event_datetime timestamptz NOT NULL, status text DEFAULT 'Upcoming'::text, notes text, created_at timestamptz DEFAULT now());\n\n-- Foreign key constraints for table: events\nALTER TABLE events ADD CONSTRAINT fk_events_user_profile FOREIGN KEY (user_id) REFERENCES user_profiles (user_id);\n\n-- RLS enabled for table: events\nALTER TABLE events ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: events\nCREATE POLICY auth_insert_events ON events FOR INSERT TO public WITH CHECK ((auth.role() = 'authenticated'::text));\nCREATE POLICY owner_update_events ON events FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON events FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read_events ON events FOR SELECT TO public USING (true);\n\n-- Data for table: events\nINSERT INTO events (id, user_id, title, details, organizer, venue, event_datetime, status, notes, created_at) VALUES ('9c60aab5-d8db-481e-8611-e430ea9b024b', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', 'Eid Al-Fitr', 'Eid al-Fitr 2026 is predicted to fall on Friday, March 20, 2026, marking the end of Ramadan. While astronomical calculations suggest this date, the exact start is confirmed by the official moon-sighting committee, which may result in celebrations beginning on March 19 or 20, 2026, depending on the region', 'Muslim community', 'various places', '2026-03-20T00:00:00.000Z', 'Upcoming', NULL, '2026-03-15T16:30:34.858Z');\n\n-- Table: feature_info\nCREATE TABLE IF NOT EXISTS feature_info (id uuid NOT NULL DEFAULT gen_random_uuid(), feature_key text NOT NULL, title text NOT NULL, summary text NOT NULL, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Indexes for table: feature_info\nCREATE UNIQUE INDEX feature_info_feature_key_key ON public.feature_info USING btree (feature_key);\n\n-- RLS enabled for table: feature_info\nALTER TABLE feature_info ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: feature_info\nCREATE POLICY \"Public read access for feature_info\" ON feature_info FOR SELECT TO public USING (true);\nCREATE POLICY project_admin_policy ON feature_info FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Data for table: feature_info\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('b19b4bec-6f9d-4986-9b60-13c199f9b57c', 'hub', 'Neighborhood Hub', 'The central command center for your community. Access all neighborhood services, see recent activities, and stay connected with your neighbors through announcements, events, and community tools.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('1d048374-7202-4722-b42b-aaad7439c995', 'leaderboard', 'Leaderboard & Rewards', 'Celebrate community engagement! Earn points for contributing—such as posting announcements or inviting neighbors. Climb the ranks, level up, and spin the Daily Wheel for bonus points. High engagement can unlock eligibility for Moderator roles.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('6a8d847a-8dd9-41cb-9407-37d10d637a11', 'whiteboard', 'Daily Whiteboard', 'Engage in daily community discussions. Every day, the community votes on a question to be featured. Answer the selected question to share your thoughts and earn engagement points.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('37d84161-644b-4381-8b89-f054f57aab9c', 'gallery', 'Community Gallery', 'A visual space for your neighborhood. Share photos of local life, events, or beauty. Vote for your favorite pictures; the top-voted \"Picture of the Day\" earns the photographer special rewards.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('13548902-df27-4066-9405-fea0c6d8dbc6', 'grievances', 'Grievances & Support', 'A transparent way to report and resolve community issues. Submit concerns directly to neighborhood management, track resolution status, and help maintain a better living environment for everyone.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('cd58d08e-9f9f-47d6-bf02-c6307affd679', 'announcements', 'Announcements', 'Stay informed with official updates and community news. Admins and members can post important information to ensure everyone is on the same page regarding neighborhood events and policies.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('09313dcc-6e58-4d3b-b2c7-ee3c87896ffa', 'classifieds', 'Classified Ads', 'Buy, sell, or trade locally. A private marketplace for neighborhood residents to list items and services, fostering a circular economy and community trust.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('8e3982e7-8b4d-4c0e-a7b9-bf53958b7760', 'events', 'Events Calendar', 'Never miss a neighborhood gathering. Browse upcoming social events, meetings, and celebrations. Get details on venues, times, and organizers all in one place.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('391d8a35-ca3e-4bc1-9e8a-8d42d61e850f', 'forum', 'Community Forum', 'The place for deep discussions. Start topics on neighborhood improvements, share tips, or ask for advice. A collaborative space for long-form community engagement.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('9478963f-e1fa-43b3-a257-e621104c9764', 'voting', 'Voting & Elections', 'Participate in neighborhood governance. Vote in board elections, weigh in on community polls, and help shape the future of your neighborhood through democratic participation.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('50688ea6-2b99-45da-b985-a6dda78f993e', 'messages', 'Direct Messaging', 'Connect privately with your neighbors. Secure, one-on-one communication to discuss specific topics, coordinate local help, or just say hello while maintaining community safety.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('c9067d6a-3055-423b-9e7f-03a9dbea4ded', 'members', 'Members Directory', 'Get to know your neighbors. A verified list of community residents with profiles and leveling information, making it easy to find and connect with people in your neighborhood.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('bd393086-8d2d-40c8-9404-aee28f02272d', 'invites', 'Invite Neighbors', 'Grow your community! Invite your real-world neighbors to join the private Jeeraan space. Earn significant engagement points when your invites are accepted and new members join.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('0cca4c03-41c6-4e53-ad1c-e538e611d4b1', 'admin', 'Admin Dashboard', 'Comprehensive tools for neighborhood management. Admins can manage access requests, moderate content, monitor engagement analytics, and configure neighborhood-wide settings.', '2026-05-09T18:41:01.681Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('da9f6c69-8b9d-40a7-a38d-74893b1bdf03', 'notes', 'Newsletter', 'Stay updated with your community! Access the latest neighborhood newsletters, important documents, meeting minutes, and local reports shared by your neighborhood administrators.', '2026-05-09T18:41:59.106Z');\nINSERT INTO feature_info (id, feature_key, title, summary, created_at) VALUES ('9fc798c4-594c-43c2-b47c-210632b2bb4f', 'q-and-a', 'Q & A', 'Neighborhood Q & A: Ask questions to your neighborhood admins. Your question will be sent privately; admins will be notified and will respond as soon as possible. They may choose to make helpful questions public for the whole community.', '2026-05-09T22:13:04.635Z');\n\n-- Table: forum_posts\nCREATE TABLE IF NOT EXISTS forum_posts (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid, title text NOT NULL, content text NOT NULL, category text NOT NULL, created_at timestamptz DEFAULT now());\n\n-- Foreign key constraints for table: forum_posts\nALTER TABLE forum_posts ADD CONSTRAINT fk_forum_posts_user_profile FOREIGN KEY (user_id) REFERENCES user_profiles (user_id);\n\n-- RLS enabled for table: forum_posts\nALTER TABLE forum_posts ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: forum_posts\nCREATE POLICY auth_insert_posts ON forum_posts FOR INSERT TO public WITH CHECK ((auth.role() = 'authenticated'::text));\nCREATE POLICY owner_update_posts ON forum_posts FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON forum_posts FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read_posts ON forum_posts FOR SELECT TO public USING (true);\n\n-- Data for table: forum_posts\nINSERT INTO forum_posts (id, user_id, title, content, category, created_at) VALUES ('d7fe040a-41d2-4fb8-bc36-f879f66ca82e', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', 'Security at LVW', 'Are you satisfied with the performance and services provided by the security company here at LVW? Last week a car that belongs to a family member got stolen around 1 am parked on the street very near to the office. In fact, with the help of the security cameras the office has we were to see the 3 guys that were are able to break the sunroof, jumped inside the car, disabled the security systems in the car, and took off. Did anyone else have their car vandalized or anything else?', 'General', '2026-03-15T18:15:42.079Z');\n\n-- Table: forum_replies\nCREATE TABLE IF NOT EXISTS forum_replies (id uuid NOT NULL DEFAULT gen_random_uuid(), post_id uuid, user_id uuid, content text NOT NULL, created_at timestamptz DEFAULT now());\n\n-- Foreign key constraints for table: forum_replies\nALTER TABLE forum_replies ADD CONSTRAINT fk_forum_replies_user_profile FOREIGN KEY (user_id) REFERENCES user_profiles (user_id);\nALTER TABLE forum_replies ADD CONSTRAINT forum_replies_post_id_fkey FOREIGN KEY (post_id) REFERENCES forum_posts (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: forum_replies\nALTER TABLE forum_replies ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: forum_replies\nCREATE POLICY auth_insert_replies ON forum_replies FOR INSERT TO public WITH CHECK ((auth.role() = 'authenticated'::text));\nCREATE POLICY owner_update_replies ON forum_replies FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON forum_replies FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read_replies ON forum_replies FOR SELECT TO public USING (true);\n\n-- Table: gallery_comments\nCREATE TABLE IF NOT EXISTS gallery_comments (id uuid NOT NULL DEFAULT gen_random_uuid(), post_id uuid, user_id uuid, content text NOT NULL, created_at timestamptz DEFAULT now());\n\n-- Indexes for table: gallery_comments\nCREATE UNIQUE INDEX gallery_comments_post_id_user_id_key ON public.gallery_comments USING btree (post_id, user_id);\n\n-- Foreign key constraints for table: gallery_comments\nALTER TABLE gallery_comments ADD CONSTRAINT gallery_comments_post_id_fkey FOREIGN KEY (post_id) REFERENCES gallery_posts (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: gallery_comments\nALTER TABLE gallery_comments ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: gallery_comments\nCREATE POLICY \"Public read gallery comments\" ON gallery_comments FOR SELECT TO public USING (true);\nCREATE POLICY \"Users can delete their own gallery comments\" ON gallery_comments FOR DELETE TO public USING ((auth.uid() = user_id));\nCREATE POLICY \"Users can insert their own gallery comments\" ON gallery_comments FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY \"Users can update their own gallery comments\" ON gallery_comments FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON gallery_comments FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: gallery_posts\nCREATE TABLE IF NOT EXISTS gallery_posts (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid, image_url text NOT NULL, storage_key text NOT NULL, description text NOT NULL, status text DEFAULT 'pending'::text, votes_count integer DEFAULT 0, created_at timestamptz DEFAULT now());\n\n-- Indexes for table: gallery_posts\nCREATE UNIQUE INDEX gallery_posts_user_date_idx ON public.gallery_posts USING btree (user_id, (((created_at AT TIME ZONE 'UTC'::text))::date));\n\n-- RLS enabled for table: gallery_posts\nALTER TABLE gallery_posts ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: gallery_posts\nCREATE POLICY \"Read gallery posts\" ON gallery_posts FOR SELECT TO public USING (((status = 'approved'::text) OR (auth.uid() = user_id)));\nCREATE POLICY \"Users can insert gallery posts\" ON gallery_posts FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON gallery_posts FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: gallery_votes\nCREATE TABLE IF NOT EXISTS gallery_votes (id uuid NOT NULL DEFAULT gen_random_uuid(), post_id uuid, user_id uuid, vote_type integer NOT NULL, created_at timestamptz DEFAULT now());\n\n-- Indexes for table: gallery_votes\nCREATE UNIQUE INDEX gallery_votes_post_id_user_id_key ON public.gallery_votes USING btree (post_id, user_id);\n\n-- Foreign key constraints for table: gallery_votes\nALTER TABLE gallery_votes ADD CONSTRAINT gallery_votes_post_id_fkey FOREIGN KEY (post_id) REFERENCES gallery_posts (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: gallery_votes\nALTER TABLE gallery_votes ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: gallery_votes\nCREATE POLICY \"Public read gallery votes\" ON gallery_votes FOR SELECT TO public USING (true);\nCREATE POLICY \"Users can delete their own gallery votes\" ON gallery_votes FOR DELETE TO public USING ((auth.uid() = user_id));\nCREATE POLICY \"Users can insert their own gallery votes\" ON gallery_votes FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY \"Users can update their own gallery votes\" ON gallery_votes FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON gallery_votes FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: gamification_settings\nCREATE TABLE IF NOT EXISTS gamification_settings (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, is_active boolean DEFAULT true, points_announcement integer DEFAULT 3, points_invite_accepted integer DEFAULT 5, points_work_order_feedback integer DEFAULT 2, points_forum_topic integer DEFAULT 2, points_classified_ad integer DEFAULT 2, points_grievance_submission integer DEFAULT 3, points_event_qna_reply integer DEFAULT 0, level_1_threshold integer DEFAULT 0, level_2_threshold integer DEFAULT 25, level_3_threshold integer DEFAULT 50, max_levels integer DEFAULT 3, moderator_threshold integer DEFAULT 25, daily_points_cap integer, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Indexes for table: gamification_settings\nCREATE UNIQUE INDEX gamification_settings_neighborhood_id_key ON public.gamification_settings USING btree (neighborhood_id);\n\n-- Foreign key constraints for table: gamification_settings\nALTER TABLE gamification_settings ADD CONSTRAINT gamification_settings_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: gamification_settings\nALTER TABLE gamification_settings ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: gamification_settings\nCREATE POLICY \"Admins can manage gamification settings\" ON gamification_settings FOR ALL TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Members can read their neighborhood gamification settings\" ON gamification_settings FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = gamification_settings.neighborhood_id)))) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON gamification_settings FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Triggers for table: gamification_settings\nCREATE TRIGGER on_gamification_settings_updated BEFORE UPDATE ON gamification_settings FOR EACH ROW EXECUTE FUNCTION handle_updated_at();\n\n-- Data for table: gamification_settings\nINSERT INTO gamification_settings (id, neighborhood_id, is_active, points_announcement, points_invite_accepted, points_work_order_feedback, points_forum_topic, points_classified_ad, points_grievance_submission, points_event_qna_reply, level_1_threshold, level_2_threshold, level_3_threshold, max_levels, moderator_threshold, daily_points_cap, created_at, updated_at) VALUES ('7fcdbd96-cec9-404c-90d9-ac75b5ec2298', '785dce54-2952-466a-9ba3-79aa59640aa0', true, 3, 5, 2, 2, 2, 3, 0, 0, 25, 50, 3, 25, NULL, '2026-04-13T00:38:25.186Z', '2026-04-13T00:38:25.186Z');\n\n-- Table: grievance_comments\nCREATE TABLE IF NOT EXISTS grievance_comments (id uuid NOT NULL DEFAULT gen_random_uuid(), grievance_id uuid, user_id uuid, content text NOT NULL, created_at timestamptz DEFAULT now());\n\n-- Foreign key constraints for table: grievance_comments\nALTER TABLE grievance_comments ADD CONSTRAINT grievance_comments_grievance_id_fkey FOREIGN KEY (grievance_id) REFERENCES grievances (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: grievance_comments\nALTER TABLE grievance_comments ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: grievance_comments\nCREATE POLICY \"Authenticated members can insert comments\" ON grievance_comments FOR INSERT TO public WITH CHECK (((auth.uid() = user_id) AND (EXISTS ( SELECT 1\n   FROM (grievances g\n     JOIN user_neighborhoods un ON ((g.neighborhood_id = un.neighborhood_id)))\n  WHERE ((g.id = grievance_comments.grievance_id) AND (un.user_id = auth.uid()))))));\nCREATE POLICY \"Members can read comments for grievances in their neighborhood\" ON grievance_comments FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM (grievances g\n     JOIN user_neighborhoods un ON ((g.neighborhood_id = un.neighborhood_id)))\n  WHERE ((g.id = grievance_comments.grievance_id) AND (un.user_id = auth.uid())))) OR is_super_admin()));\nCREATE POLICY owner_insert ON grievance_comments FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON grievance_comments FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read ON grievance_comments FOR SELECT TO public USING (true);\n\n-- Triggers for table: grievance_comments\nCREATE TRIGGER on_grievance_comments_updated BEFORE UPDATE ON grievance_comments FOR EACH ROW EXECUTE FUNCTION handle_updated_at();\n\n-- Table: grievances\nCREATE TABLE IF NOT EXISTS grievances (id uuid NOT NULL DEFAULT gen_random_uuid(), title text NOT NULL, description text NOT NULL, category text NOT NULL, status text NOT NULL DEFAULT 'Pending'::text, user_id uuid, views_count integer DEFAULT 0, images ARRAY DEFAULT '{}'::text[], created_at timestamptz DEFAULT now(), neighborhood_id uuid NOT NULL);\n\n-- Foreign key constraints for table: grievances\nALTER TABLE grievances ADD CONSTRAINT fk_grievances_user_profile FOREIGN KEY (user_id) REFERENCES user_profiles (user_id);\nALTER TABLE grievances ADD CONSTRAINT grievances_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: grievances\nALTER TABLE grievances ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: grievances\nCREATE POLICY \"Authenticated members can insert grievances\" ON grievances FOR INSERT TO public WITH CHECK (((auth.uid() = user_id) AND (EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = grievances.neighborhood_id))))));\nCREATE POLICY \"Members can read grievances in their neighborhood\" ON grievances FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = grievances.neighborhood_id)))) OR is_super_admin()));\nCREATE POLICY \"Owners or admins can update grievances\" ON grievances FOR UPDATE TO public USING (((auth.uid() = user_id) OR is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY owner_insert ON grievances FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY owner_update ON grievances FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON grievances FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read ON grievances FOR SELECT TO public USING (true);\n\n-- Triggers for table: grievances\nCREATE TRIGGER on_grievances_updated BEFORE UPDATE ON grievances FOR EACH ROW EXECUTE FUNCTION handle_updated_at();\n\n-- Data for table: grievances\nINSERT INTO grievances (id, title, description, category, status, user_id, views_count, images, created_at, neighborhood_id) VALUES ('ba64ed03-a06a-422c-a8e0-53e4ca0caaed', 'Unauthorized Removal from Membership Certificate & Lack of Written Response', 'I am submitting this grievance regarding my membership status with Loma Vista West Townhouses.\n\nI previously submitted a written request asking for official confirmation of the membership records for my Unit, including the names listed on the membership certificate and any documented changes since my original agreements in 2000. Despite this formal request, I have not received any written response.\n\nHowever, I was verbally informed that my name was removed from the membership certificate and that the current certificate reflects only my wife’s name. Critically, I was also informed that there is no consent letter or authorization on file from me approving this change.\n\nThis raises serious concerns, as I have been a continuous resident since 2000, an original executing member, and have remained in good standing with no history of delinquency.\n\nAdditionally, I have been informed that I am not eligible to participate in or hold office in any committees due to my alleged non-membership status. Attempts to seek clarification have been unsuccessful, and I am currently unable to obtain further information as communication has been limited.\n\nKey concerns:\n\nRemoval of my name from the membership certificate without my knowledge or consent.\nAbsence of any documented authorization for this change.\nFailure to provide written confirmation of membership records upon formal request.\nDenial of participation rights based on potentially inaccurate records.', 'Maintenance', 'Pending', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', 6, '[]', '2026-03-25T03:37:20.303Z', '785dce54-2952-466a-9ba3-79aa59640aa0');\n\n-- Table: invites\nCREATE TABLE IF NOT EXISTS invites (id uuid NOT NULL DEFAULT gen_random_uuid(), code text NOT NULL, neighborhood_id uuid NOT NULL, phone text NOT NULL, expires_at timestamptz NOT NULL, used_at timestamptz, created_by uuid, created_at timestamptz DEFAULT now());\n\n-- Indexes for table: invites\nCREATE UNIQUE INDEX invites_code_key ON public.invites USING btree (code);\n\n-- Foreign key constraints for table: invites\nALTER TABLE invites ADD CONSTRAINT invites_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: invites\nALTER TABLE invites ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: invites\nCREATE POLICY invites_admin_all ON invites FOR ALL TO public USING (is_admin_of(neighborhood_id));\nCREATE POLICY invites_anon_select ON invites FOR SELECT TO public USING (true);\nCREATE POLICY project_admin_policy ON invites FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: join_requests\nCREATE TABLE IF NOT EXISTS join_requests (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, name text NOT NULL, phone text NOT NULL, status text DEFAULT 'pending'::text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), email text, created_by uuid, address text, is_public boolean DEFAULT true, approval_method text DEFAULT 'twilio'::text, approved_by uuid, invite_code text);\n\n-- Indexes for table: join_requests\nCREATE UNIQUE INDEX join_requests_email_unique ON public.join_requests USING btree (neighborhood_id, email);\nCREATE UNIQUE INDEX join_requests_phone_unique ON public.join_requests USING btree (neighborhood_id, phone);\n\n-- Foreign key constraints for table: join_requests\nALTER TABLE join_requests ADD CONSTRAINT join_requests_approved_by_fkey FOREIGN KEY (approved_by) REFERENCES user_profiles (user_id);\nALTER TABLE join_requests ADD CONSTRAINT join_requests_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: join_requests\nALTER TABLE join_requests ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: join_requests\nCREATE POLICY join_requests_admin_all ON join_requests FOR ALL TO public USING (is_admin_of(neighborhood_id));\nCREATE POLICY join_requests_anon_insert ON join_requests FOR INSERT TO public WITH CHECK (true);\nCREATE POLICY join_requests_created_by_select ON join_requests FOR SELECT TO public USING ((auth.uid() = created_by));\nCREATE POLICY project_admin_policy ON join_requests FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: messages\nCREATE TABLE IF NOT EXISTS messages (id uuid NOT NULL DEFAULT gen_random_uuid(), conversation_id uuid NOT NULL, sender_id uuid NOT NULL, neighborhood_id uuid NOT NULL, content text NOT NULL, attachment_url text, attachment_type text, is_read boolean DEFAULT false, is_flagged boolean DEFAULT false, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Foreign key constraints for table: messages\nALTER TABLE messages ADD CONSTRAINT messages_conversation_id_fkey FOREIGN KEY (conversation_id) REFERENCES conversations (id) ON DELETE CASCADE;\nALTER TABLE messages ADD CONSTRAINT messages_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\nALTER TABLE messages ADD CONSTRAINT messages_sender_id_fkey FOREIGN KEY (sender_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: messages\nALTER TABLE messages ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: messages\nCREATE POLICY \"Users can insert messages in their conversations\" ON messages FOR INSERT TO public WITH CHECK (((auth.uid() = sender_id) AND (EXISTS ( SELECT 1\n   FROM conversations\n  WHERE ((conversations.id = messages.conversation_id) AND ((auth.uid() = conversations.participant_1_id) OR (auth.uid() = conversations.participant_2_id))))) AND (EXISTS ( SELECT 1\n   FROM neighborhoods\n  WHERE ((neighborhoods.id = messages.neighborhood_id) AND (neighborhoods.is_dm_enabled = true)))) AND (EXISTS ( SELECT 1\n   FROM (user_daily_usage udu\n     JOIN neighborhoods n ON ((n.id = messages.neighborhood_id)))\n  WHERE ((udu.user_id = auth.uid()) AND (udu.usage_date = CURRENT_DATE) AND (udu.messages_sent_count < n.max_daily_messages))\nUNION ALL\n SELECT 1\n   FROM neighborhoods n\n  WHERE ((n.id = messages.neighborhood_id) AND (NOT (EXISTS ( SELECT 1\n           FROM user_daily_usage\n          WHERE ((user_daily_usage.user_id = auth.uid()) AND (user_daily_usage.usage_date = CURRENT_DATE))))))))));\nCREATE POLICY \"Users can read messages in their conversations\" ON messages FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM conversations\n  WHERE ((conversations.id = messages.conversation_id) AND (((auth.uid() = conversations.participant_1_id) OR (auth.uid() = conversations.participant_2_id)) OR is_admin_of(conversations.neighborhood_id))))) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON messages FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Triggers for table: messages\nCREATE TRIGGER on_new_message AFTER INSERT ON messages FOR EACH ROW EXECUTE FUNCTION handle_new_message();\n\n-- Table: neighborhood_election_info\nCREATE TABLE IF NOT EXISTS neighborhood_election_info (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, voting_date date NOT NULL, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Indexes for table: neighborhood_election_info\nCREATE UNIQUE INDEX neighborhood_election_info_neighborhood_id_key ON public.neighborhood_election_info USING btree (neighborhood_id);\n\n-- RLS enabled for table: neighborhood_election_info\nALTER TABLE neighborhood_election_info ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: neighborhood_election_info\nCREATE POLICY \"Members can read election info\" ON neighborhood_election_info FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = neighborhood_election_info.neighborhood_id)))) OR (EXISTS ( SELECT 1\n   FROM user_profiles\n  WHERE ((user_profiles.user_id = auth.uid()) AND (user_profiles.global_role = 'super_admin'::global_role))))));\nCREATE POLICY \"Super admins can manage election info\" ON neighborhood_election_info FOR ALL TO public USING ((EXISTS ( SELECT 1\n   FROM user_profiles\n  WHERE ((user_profiles.user_id = auth.uid()) AND (user_profiles.global_role = 'super_admin'::global_role)))));\nCREATE POLICY project_admin_policy ON neighborhood_election_info FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Triggers for table: neighborhood_election_info\nCREATE TRIGGER on_neighborhood_election_info_updated BEFORE UPDATE ON neighborhood_election_info FOR EACH ROW EXECUTE FUNCTION handle_updated_at();\n\n-- Data for table: neighborhood_election_info\nINSERT INTO neighborhood_election_info (id, neighborhood_id, voting_date, created_at, updated_at) VALUES ('67aa8c97-0303-4948-ae78-d9e803b2f52f', '785dce54-2952-466a-9ba3-79aa59640aa0', '2026-05-17T00:00:00.000Z', '2026-03-17T13:31:22.332Z', '2026-05-03T16:31:44.061Z');\n\n-- Table: neighborhood_notes\nCREATE TABLE IF NOT EXISTS neighborhood_notes (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, title text NOT NULL, message text NOT NULL, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Foreign key constraints for table: neighborhood_notes\nALTER TABLE neighborhood_notes ADD CONSTRAINT neighborhood_notes_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: neighborhood_notes\nALTER TABLE neighborhood_notes ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: neighborhood_notes\nCREATE POLICY \"Admins can manage neighborhood notes\" ON neighborhood_notes FOR ALL TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Members can read notes for their neighborhood\" ON neighborhood_notes FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = neighborhood_notes.neighborhood_id)))) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON neighborhood_notes FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Triggers for table: neighborhood_notes\nCREATE TRIGGER on_neighborhood_notes_updated BEFORE UPDATE ON neighborhood_notes FOR EACH ROW EXECUTE FUNCTION handle_updated_at();\n\n-- Data for table: neighborhood_notes\nINSERT INTO neighborhood_notes (id, neighborhood_id, title, message, created_at, updated_at) VALUES ('e3908e2d-9451-474b-b588-6c3b4fa5d58c', '785dce54-2952-466a-9ba3-79aa59640aa0', 'memberships for sale', 'there are 7 available and they are a mix', '2026-04-23T03:13:20.815Z', '2026-04-23T03:13:20.815Z');\n\n-- Table: neighborhood_settings\nCREATE TABLE IF NOT EXISTS neighborhood_settings (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, classifieds_monetization_enabled boolean DEFAULT false, max_ads_resident integer DEFAULT 5, max_ads_moderator integer DEFAULT 10, max_ads_admin integer DEFAULT 20, ad_expiry_days integer DEFAULT 30, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Indexes for table: neighborhood_settings\nCREATE UNIQUE INDEX neighborhood_settings_neighborhood_id_key ON public.neighborhood_settings USING btree (neighborhood_id);\n\n-- Foreign key constraints for table: neighborhood_settings\nALTER TABLE neighborhood_settings ADD CONSTRAINT neighborhood_settings_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: neighborhood_settings\nALTER TABLE neighborhood_settings ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: neighborhood_settings\nCREATE POLICY \"Admins can manage neighborhood settings\" ON neighborhood_settings FOR ALL TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Members can read neighborhood settings\" ON neighborhood_settings FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = neighborhood_settings.neighborhood_id)))) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON neighborhood_settings FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: neighborhoods\nCREATE TABLE IF NOT EXISTS neighborhoods (id uuid NOT NULL DEFAULT gen_random_uuid(), name text NOT NULL, address text NOT NULL, city text NOT NULL, state text NOT NULL, zip_code text NOT NULL, admin_contact_info text, created_at timestamptz DEFAULT now(), is_dm_enabled boolean DEFAULT true, max_daily_messages integer DEFAULT 10);\n\n-- RLS enabled for table: neighborhoods\nALTER TABLE neighborhoods ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: neighborhoods\nCREATE POLICY neighborhoods_admin_all ON neighborhoods FOR ALL TO public USING (is_admin_of(id));\nCREATE POLICY neighborhoods_insert_auth ON neighborhoods FOR INSERT TO public WITH CHECK ((auth.role() = 'authenticated'::text));\nCREATE POLICY neighborhoods_public_read ON neighborhoods FOR SELECT TO public USING (true);\nCREATE POLICY project_admin_policy ON neighborhoods FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Data for table: neighborhoods\nINSERT INTO neighborhoods (id, name, address, city, state, zip_code, admin_contact_info, created_at, is_dm_enabled, max_daily_messages) VALUES ('785dce54-2952-466a-9ba3-79aa59640aa0', 'Loma Vista West Townhomes', '7532 Loma Vista Dr  ', 'Kansas City', 'MO', '64138', NULL, '2026-03-15T15:59:54.657Z', true, 10);\n\n-- Table: notifications\nCREATE TABLE IF NOT EXISTS notifications (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid NOT NULL, title text NOT NULL, message text NOT NULL, type text DEFAULT 'info'::text, is_read boolean DEFAULT false, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Foreign key constraints for table: notifications\nALTER TABLE notifications ADD CONSTRAINT notifications_user_id_fkey FOREIGN KEY (user_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: notifications\nALTER TABLE notifications ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: notifications\nCREATE POLICY \"System can insert notifications\" ON notifications FOR INSERT TO public WITH CHECK (true);\nCREATE POLICY \"Users can read their own notifications\" ON notifications FOR SELECT TO public USING ((auth.uid() = user_id));\nCREATE POLICY \"Users can update their own notifications\" ON notifications FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON notifications FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: points_log\nCREATE TABLE IF NOT EXISTS points_log (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid NOT NULL, neighborhood_id uuid NOT NULL, action_type text NOT NULL, points_awarded integer NOT NULL, entity_id uuid, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Foreign key constraints for table: points_log\nALTER TABLE points_log ADD CONSTRAINT points_log_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\nALTER TABLE points_log ADD CONSTRAINT points_log_user_id_fkey FOREIGN KEY (user_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: points_log\nALTER TABLE points_log ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: points_log\nCREATE POLICY \"Admins can read points log for their neighborhood\" ON points_log FOR SELECT TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Users can read their own points log\" ON points_log FOR SELECT TO public USING (((user_id = auth.uid()) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON points_log FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: poll_votes\nCREATE TABLE IF NOT EXISTS poll_votes (id uuid NOT NULL DEFAULT gen_random_uuid(), poll_id uuid, candidate_id uuid, user_id uuid, device_fingerprint text, ip_address text, created_at timestamptz DEFAULT now());\n\n-- Indexes for table: poll_votes\nCREATE UNIQUE INDEX poll_votes_poll_id_user_id_key ON public.poll_votes USING btree (poll_id, user_id);\n\n-- Foreign key constraints for table: poll_votes\nALTER TABLE poll_votes ADD CONSTRAINT poll_votes_candidate_id_fkey FOREIGN KEY (candidate_id) REFERENCES candidates (id) ON DELETE CASCADE;\nALTER TABLE poll_votes ADD CONSTRAINT poll_votes_poll_id_fkey FOREIGN KEY (poll_id) REFERENCES polls (id) ON DELETE CASCADE;\nALTER TABLE poll_votes ADD CONSTRAINT poll_votes_user_id_fkey FOREIGN KEY (user_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: poll_votes\nALTER TABLE poll_votes ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: poll_votes\nCREATE POLICY owner_write_poll_votes ON poll_votes FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON poll_votes FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read_poll_votes ON poll_votes FOR SELECT TO public USING (true);\n\n-- Table: polls\nCREATE TABLE IF NOT EXISTS polls (id uuid NOT NULL DEFAULT gen_random_uuid(), title text NOT NULL, description text, end_time timestamptz, created_by uuid, created_at timestamptz DEFAULT now(), neighborhood_id uuid, type text NOT NULL DEFAULT 'general'::text);\n\n-- Foreign key constraints for table: polls\nALTER TABLE polls ADD CONSTRAINT polls_created_by_fkey FOREIGN KEY (created_by) REFERENCES user_profiles (user_id) ON DELETE SET NULL;\nALTER TABLE polls ADD CONSTRAINT polls_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: polls\nALTER TABLE polls ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: polls\nCREATE POLICY \"Members can read their neighborhood polls\" ON polls FOR SELECT TO public USING (((EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = polls.neighborhood_id)))) OR is_super_admin()));\nCREATE POLICY owner_write_polls ON polls FOR INSERT TO public WITH CHECK ((auth.uid() = created_by));\nCREATE POLICY project_admin_policy ON polls FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Data for table: polls\nINSERT INTO polls (id, title, description, end_time, created_by, created_at, neighborhood_id, type) VALUES ('f5b8353e-01bc-4359-8e02-147c480ba117', 'Yard of the Season - Spring 2026', 'Vote for the most beautiful yard in our community this spring!', '2026-05-15T23:59:59.000Z', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', '2026-03-17T13:35:47.151Z', '785dce54-2952-466a-9ba3-79aa59640aa0', 'general');\nINSERT INTO polls (id, title, description, end_time, created_by, created_at, neighborhood_id, type) VALUES ('52020fe2-80c9-46ac-84e8-8bfaac5e1d4b', 'Board Member Election 2026', 'Vote for your favorite candidates for the next Board of Directors!', '2026-11-15T23:59:59.000Z', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', '2026-03-17T13:31:38.865Z', '785dce54-2952-466a-9ba3-79aa59640aa0', 'election');\n\n-- Table: questions\nCREATE TABLE IF NOT EXISTS questions (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid NOT NULL, member_id uuid NOT NULL, question_text text NOT NULL, answer_text text, is_public boolean DEFAULT false, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()));\n\n-- Foreign key constraints for table: questions\nALTER TABLE questions ADD CONSTRAINT questions_member_id_fkey FOREIGN KEY (member_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\nALTER TABLE questions ADD CONSTRAINT questions_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: questions\nALTER TABLE questions ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: questions\nCREATE POLICY \"Admins can delete questions\" ON questions FOR DELETE TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Admins can update questions\" ON questions FOR UPDATE TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Members can insert their own questions\" ON questions FOR INSERT TO public WITH CHECK (((auth.uid() = member_id) AND (EXISTS ( SELECT 1\n   FROM user_neighborhoods\n  WHERE ((user_neighborhoods.user_id = auth.uid()) AND (user_neighborhoods.neighborhood_id = questions.neighborhood_id))))));\nCREATE POLICY \"Members can read public questions or their own\" ON questions FOR SELECT TO public USING (((is_public = true) OR (member_id = auth.uid()) OR is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON questions FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Triggers for table: questions\nCREATE TRIGGER on_questions_updated BEFORE UPDATE ON questions FOR EACH ROW EXECUTE FUNCTION handle_updated_at();\n\n-- Table: service_orders\nCREATE TABLE IF NOT EXISTS service_orders (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid, unit_address text NOT NULL, occupant_name text NOT NULL, issue_description text NOT NULL, maintenance_person text, satisfaction_rating integer, complete_on date, status text DEFAULT 'Pending'::text, created_at timestamptz DEFAULT now(), feedback text);\n\n-- RLS enabled for table: service_orders\nALTER TABLE service_orders ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: service_orders\nCREATE POLICY authenticated_insert ON service_orders FOR INSERT TO public WITH CHECK ((auth.role() = 'authenticated'::text));\nCREATE POLICY owner_update ON service_orders FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON service_orders FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY public_read ON service_orders FOR SELECT TO public USING (true);\n\n-- Data for table: service_orders\nINSERT INTO service_orders (id, user_id, unit_address, occupant_name, issue_description, maintenance_person, satisfaction_rating, complete_on, status, created_at, feedback) VALUES ('c2f30297-4f8c-44df-b231-73ec2513cfff', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', '7618 Loma Vista Dr', 'Bashir', 'Leak under the toilet seat in the upstairs bathroom.', 'David', 2, '2025-09-09T00:00:00.000Z', 'Pending', '2025-08-19T05:00:00.000Z', 'It took two different maintenance people 5 visits to complete the work (8/19, 8/26, 8/28, 9/4, and 9/9). On the second visit the person that came to fix the issue started the work then decided that he needed additional parts only to go to the office to tell them that the toilet seat was dirty which was a lie and that they needed to send someone again to check if it was cleaned. The other maintenance guy would finish part of the work and decides that he would come the next day to complete everything but of course no show as they promised.');\n\n-- Table: user_daily_usage\nCREATE TABLE IF NOT EXISTS user_daily_usage (user_id uuid NOT NULL, usage_date date NOT NULL DEFAULT CURRENT_DATE, messages_sent_count integer DEFAULT 0);\n\n-- Foreign key constraints for table: user_daily_usage\nALTER TABLE user_daily_usage ADD CONSTRAINT user_daily_usage_user_id_fkey FOREIGN KEY (user_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: user_daily_usage\nALTER TABLE user_daily_usage ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: user_daily_usage\nCREATE POLICY \"Users can read their own daily usage\" ON user_daily_usage FOR SELECT TO public USING (((user_id = auth.uid()) OR is_super_admin()));\nCREATE POLICY project_admin_policy ON user_daily_usage FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: user_neighborhoods\nCREATE TABLE IF NOT EXISTS user_neighborhoods (id uuid NOT NULL DEFAULT gen_random_uuid(), user_id uuid NOT NULL, neighborhood_id uuid NOT NULL, role text DEFAULT 'resident'::text, joined_at timestamptz DEFAULT now(), is_blocked boolean DEFAULT false);\n\n-- Indexes for table: user_neighborhoods\nCREATE UNIQUE INDEX user_neighborhoods_user_id_key ON public.user_neighborhoods USING btree (user_id);\n\n-- Foreign key constraints for table: user_neighborhoods\nALTER TABLE user_neighborhoods ADD CONSTRAINT user_neighborhoods_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\nALTER TABLE user_neighborhoods ADD CONSTRAINT user_neighborhoods_user_id_profiles_fkey FOREIGN KEY (user_id) REFERENCES user_profiles (user_id) ON DELETE CASCADE;\n\n-- RLS enabled for table: user_neighborhoods\nALTER TABLE user_neighborhoods ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: user_neighborhoods\nCREATE POLICY project_admin_policy ON user_neighborhoods FOR ALL TO project_admin USING (true) WITH CHECK (true);\nCREATE POLICY user_neighborhoods_admin_all ON user_neighborhoods FOR ALL TO public USING (is_admin_of(neighborhood_id));\nCREATE POLICY user_neighborhoods_insert_self ON user_neighborhoods FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY user_neighborhoods_read_own ON user_neighborhoods FOR SELECT TO public USING ((auth.uid() = user_id));\n\n-- Data for table: user_neighborhoods\nINSERT INTO user_neighborhoods (id, user_id, neighborhood_id, role, joined_at, is_blocked) VALUES ('39849f44-ebf3-4d94-9d5a-d23968ef159f', '8239b06a-dcae-4ccf-9543-d594cd8f7e65', '785dce54-2952-466a-9ba3-79aa59640aa0', 'admin', '2026-03-15T15:59:54.864Z', false);\n\n-- Table: user_profiles\nCREATE TABLE IF NOT EXISTS user_profiles (user_id uuid NOT NULL, global_role USER-DEFINED NOT NULL DEFAULT 'user'::global_role, created_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc'::text, now()), full_name text, avatar_url text, phone text, email text, birthday date, language text, work_title text, gender text, address text, is_active boolean DEFAULT true, deletion_requested boolean DEFAULT false, points integer DEFAULT 0, level integer DEFAULT 1, eligible_for_moderator boolean DEFAULT false, is_visible boolean DEFAULT true, anonymous_id text, social_links jsonb DEFAULT '{}'::jsonb);\n\n-- RLS enabled for table: user_profiles\nALTER TABLE user_profiles ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: user_profiles\nCREATE POLICY \"Neighborhood members can see each other's profiles\" ON user_profiles FOR SELECT TO public USING ((EXISTS ( SELECT 1\n   FROM (user_neighborhoods un1\n     JOIN user_neighborhoods un2 ON ((un1.neighborhood_id = un2.neighborhood_id)))\n  WHERE ((un1.user_id = auth.uid()) AND (un2.user_id = user_profiles.user_id)))));\nCREATE POLICY \"Super admins can manage all profiles\" ON user_profiles FOR ALL TO public USING (is_super_admin());\nCREATE POLICY \"Super admins can read all profiles\" ON user_profiles FOR SELECT TO public USING (is_super_admin());\nCREATE POLICY \"Users can insert their own profile\" ON user_profiles FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY \"Users can read their own profile\" ON user_profiles FOR SELECT TO public USING ((auth.uid() = user_id));\nCREATE POLICY \"Users can update their own profile\" ON user_profiles FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON user_profiles FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Data for table: user_profiles\nINSERT INTO user_profiles (user_id, global_role, created_at, updated_at, full_name, avatar_url, phone, email, birthday, language, work_title, gender, address, is_active, deletion_requested, points, level, eligible_for_moderator, is_visible, anonymous_id, social_links) VALUES ('8239b06a-dcae-4ccf-9543-d594cd8f7e65', 'super_admin', '2026-03-14T22:52:13.517Z', '2026-05-08T04:32:10.615Z', 'Super Admin', 'https://5gvd6vyw.us-east.insforge.app/api/storage/buckets/avatars/objects/8239b06a-dcae-4ccf-9543-d594cd8f7e65-1777742086301.jpg', '913 555 5555', 'super@admin.test', '1980-08-27T00:00:00.000Z', '', 'Founder and Creator', '', NULL, true, false, 0, 1, false, true, 'dvhp61', '{\"linkedin\":\"https://www.linkedin.com/in/simon-sameer-bashir/\",\"instagram\":\"https://www.instagram.com/halayuba/\"}');\n\n-- Table: waitlist_requests\nCREATE TABLE IF NOT EXISTS waitlist_requests (id uuid NOT NULL DEFAULT gen_random_uuid(), neighborhood_id uuid, full_name text NOT NULL, phone_number text NOT NULL, email_address text NOT NULL, floorplan_interest text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());\n\n-- Indexes for table: waitlist_requests\nCREATE UNIQUE INDEX waitlist_requests_email_unique ON public.waitlist_requests USING btree (neighborhood_id, email_address);\nCREATE UNIQUE INDEX waitlist_requests_phone_unique ON public.waitlist_requests USING btree (neighborhood_id, phone_number);\n\n-- Foreign key constraints for table: waitlist_requests\nALTER TABLE waitlist_requests ADD CONSTRAINT waitlist_requests_neighborhood_id_fkey FOREIGN KEY (neighborhood_id) REFERENCES neighborhoods (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: waitlist_requests\nALTER TABLE waitlist_requests ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: waitlist_requests\nCREATE POLICY \"Admins can view waitlist requests\" ON waitlist_requests FOR SELECT TO public USING ((is_admin_of(neighborhood_id) OR is_super_admin()));\nCREATE POLICY \"Anyone can submit a waitlist request\" ON waitlist_requests FOR INSERT TO public WITH CHECK (true);\nCREATE POLICY project_admin_policy ON waitlist_requests FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: whiteboard_answers\nCREATE TABLE IF NOT EXISTS whiteboard_answers (id uuid NOT NULL DEFAULT gen_random_uuid(), question_id uuid, user_id uuid, answer_text text NOT NULL, created_at timestamptz DEFAULT now());\n\n-- Indexes for table: whiteboard_answers\nCREATE UNIQUE INDEX whiteboard_answers_question_id_user_id_key ON public.whiteboard_answers USING btree (question_id, user_id);\n\n-- Foreign key constraints for table: whiteboard_answers\nALTER TABLE whiteboard_answers ADD CONSTRAINT whiteboard_answers_question_id_fkey FOREIGN KEY (question_id) REFERENCES whiteboard_questions (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: whiteboard_answers\nALTER TABLE whiteboard_answers ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: whiteboard_answers\nCREATE POLICY \"Public read whiteboard answers\" ON whiteboard_answers FOR SELECT TO public USING (true);\nCREATE POLICY \"Users can delete their own answers\" ON whiteboard_answers FOR DELETE TO public USING ((auth.uid() = user_id));\nCREATE POLICY \"Users can insert their own answers\" ON whiteboard_answers FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY \"Users can update their own answers\" ON whiteboard_answers FOR UPDATE TO public USING ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON whiteboard_answers FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: whiteboard_questions\nCREATE TABLE IF NOT EXISTS whiteboard_questions (id uuid NOT NULL DEFAULT gen_random_uuid(), question_text text NOT NULL, category text NOT NULL, target_date date NOT NULL, is_published boolean DEFAULT false, created_at timestamptz DEFAULT now());\n\n-- RLS enabled for table: whiteboard_questions\nALTER TABLE whiteboard_questions ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: whiteboard_questions\nCREATE POLICY \"Public read whiteboard questions\" ON whiteboard_questions FOR SELECT TO public USING (true);\nCREATE POLICY project_admin_policy ON whiteboard_questions FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n-- Table: whiteboard_votes\nCREATE TABLE IF NOT EXISTS whiteboard_votes (id uuid NOT NULL DEFAULT gen_random_uuid(), question_id uuid, user_id uuid, created_at timestamptz DEFAULT now());\n\n-- Indexes for table: whiteboard_votes\nCREATE UNIQUE INDEX whiteboard_votes_question_id_user_id_key ON public.whiteboard_votes USING btree (question_id, user_id);\n\n-- Foreign key constraints for table: whiteboard_votes\nALTER TABLE whiteboard_votes ADD CONSTRAINT whiteboard_votes_question_id_fkey FOREIGN KEY (question_id) REFERENCES whiteboard_questions (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: whiteboard_votes\nALTER TABLE whiteboard_votes ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: whiteboard_votes\nCREATE POLICY \"Public read whiteboard votes\" ON whiteboard_votes FOR SELECT TO public USING (true);\nCREATE POLICY \"Users can insert their own votes\" ON whiteboard_votes FOR INSERT TO public WITH CHECK ((auth.uid() = user_id));\nCREATE POLICY project_admin_policy ON whiteboard_votes FOR ALL TO project_admin USING (true) WITH CHECK (true);\n\n","timestamp":"2026-05-19T00:48:25.970Z"}